settings.custom_css:
.scroll-left{
    opacity: 0;
    transition: 0.5s;
    transform: translate(-30px, 0);
}

.scroll-left1{
    opacity: 0;
    transition-delay: 0.5s !important;
    transition: 0.5s;
    transform: translate(-30px, 0);
}

.scroll-right{
    opacity: 0;
    transition: 0.5s;
    transform: translate(30px, 0);
}

.scroll-right1{
    opacity: 0;
    transition-delay: 0.3s !important;
    transition: 0.5s;
    transform: translate(30px, 0);
}

.scroll-right2{
    opacity: 0;
    transition-delay: 0.6s !important;
    transition: 0.5s;
    transform: translate(30px, 0);
}

.scroll-top{
    opacity: 0;
    transition: 0.5s;
    transform: translate(0, -30px);
}

.scroll-bottom{
    opacity: 0;
    transition: 0.5s;
    transform: translate(0, 30px);
}

.scroll-bottom1{
    opacity: 0;
    transition-delay: 0.2s !important;
    transition: 0.5s;
    transform: translate(0, 30px);
}

.scroll-bottom2{
    opacity: 0;
    transition-delay: 0.4s !important;
    transition: 0.5s;
    transform: translate(0, 30px);
}

.scroll-bottom3{
    opacity: 0;
    transition-delay: 0.6s !important;
    transition: 0.5s;
    transform: translate(0, 30px);
}

.blur{
    transform: scale(0.9);
    opacity: 0;
    filter: blur(20px);
    transition: 0.5s !important
}

.lista .elementor-icon-list-item{
    opacity: 0;
    transition: .5s all;
    transform: translate3d(-30px, 0, 0);
    filter: blur(10px);
}

.lista .elementor-icon-list-item.ativo{
    opacity: 1;
    transition: .5s all;
    transform: translate3d(0, 0, 0);
    filter: blur(0px);
}

.ativo{
    opacity: 1;
    transition: 0.5s;
    transform: translate(0, 0);
    transform: scale(1);
    filter: blur(0px);
}
